blocks.content:
An **object** is a collection of related data and methods organized as key-value pairs:

```javascript
let person = {
  name: "Alice",
  age: 25,
  city: "New York"
};
```

Access values using dot notation or brackets:

```javascript
console.log(person.name);      // "Alice"
console.log(person["age"]);    // 25

// Change values
person.age = 26;
person.city = "Boston";

// Add new properties
person.job = "Developer";
```

Objects are great for grouping related information about one thing (a person, product, book, etc.)

blocks.starterCode:
// Create an object
let student = {
  name: "Bob",
  grade: 10,
  gpa: 3.8,
  school: "Central High"
};

// Access properties
console.log(student.name);
console.log(student["grade"]);

// Modify properties
student.gpa = 3.9;
console.log(student.gpa);

// Add new property
student.club = "Robotics";
console.log(student);

blocks.content:
Objects can contain functions, called **methods**:

```javascript
let calculator = {
  add: function(a, b) {
    return a + b;
  },
  subtract: function(a, b) {
    return a - b;
  }
};

calculator.add(5, 3);      // 8
calculator.subtract(10, 4); // 6
```

Or using shorthand (modern JavaScript):

```javascript
let calculator = {
  add(a, b) {
    return a + b;
  },
  subtract(a, b) {
    return a - b;
  }
};
```

blocks.starterCode:
// Object with methods
let car = {
  brand: "Toyota",
  year: 2020,
  start: function() {
    console.log(this.brand + " is starting!");
  },
  stop: function() {
    console.log(this.brand + " stopped.");
  },
  honk: function() {
    console.log("Beep! Beep!");
  }
};

// Call methods
car.start();
car.honk();
car.stop();

// Access properties
console.log("Year: " + car.year);

blocks.content:
Often you'll have an array containing multiple objects:

```javascript
let students = [
  { name: "Alice", age: 20, grade: "A" },
  { name: "Bob", age: 21, grade: "B" },
  { name: "Charlie", age: 20, grade: "A" }
];

// Access items
console.log(students[0].name);  // "Alice"
console.log(students[1].age);   // 21

// Loop through
for (let student of students) {
  console.log(student.name + " has grade " + student.grade);
}
```

This pattern is very common when working with data!

blocks.starterCode:
// Array of book objects
let books = [
  { title: "JavaScript Basics", author: "John Doe", pages: 350 },
  { title: "Web Development", author: "Jane Smith", pages: 480 },
  { title: "React Guide", author: "Bob Johnson", pages: 420 }
];

// Access individual book
console.log(books[0].title);

// Loop through all books
for (let book of books) {
  console.log(book.title + " by " + book.author);
}

// Find total pages
let totalPages = books.reduce((sum, book) => sum + book.pages, 0);
console.log("Total pages: " + totalPages);
